AEJ,CAGA,yBACI,WACI,cACJ,CAEA,UACI,cACJ,CAEA,6BAEI,cAAe,CACf,iBACJ,CAEA,SACI,cAAe,CAEf,cAAe,CADf,iBAEJ,CAEA,WACI,iBACJ,CAMA,yBACI,cACJ,CAEA,eACI,cACJ,CAEA,UAEI,cAAe,CADf,gBAEJ,CACJ,CCrSA,gBAII,kBAAmB,CAFnB,uBAAyB,CACzB,YAAa,CAEb,sBAAuB,CAJvB,gBAAiB,CAKjB,YACJ,CAEA,mBACI,eAAgB,CAEhB,iBAAkB,CADlB,UAEJ,CAEA,eAGI,aAAc,CAFd,cAAe,CACf,eAAiB,CAEjB,kBACJ,CAEA,kBAEI,aAAc,CADd,cAAe,CAEf,kBACJ,CAEA,iBAGI,aAAS,CAFT,YAAa,CAEb,QAAS,CADT,6BAEJ,CAEA,aACI,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CAEnB,cAAe,CADf,iBAAkB,CAGlB,iBAAkB,CADlB,uBAEJ,CAEI,mBAGI,wBAAyB,CADzB,oBAAqB,CAErB,0CAA+C,CAH/C,kCAA2B,CAA3B,0BAIJ,CAEJ,UAEI,aAAc,CADd,cAAe,CAEf,kBACJ,CAEA,WAKI,aAAc,CAFd,aAAc,CAFd,cAAe,CACf,eAAiB,CAEjB,kBAEJ,CAEA,UAEI,aAAc,CADd,cAEJ,CAEA,yBACI,iBAEI,QAAS,CADT,yBAEJ,CAEA,eACI,cACJ,CAEA,kBACI,cACJ,CAEA,UACI,cACJ,CAEA,WACI,cACJ,CACJ","sources":["index.css","App.css","components/WelcomeScreen.css"],"sourcesContent":["* {\r\n  box-sizing: border-box;\r\n  font-family: sans-serif;\r\n}\r\n\r\nhtml,\r\nbody {\r\n  margin: 0;\r\n  padding: 0;\r\n}\r\n","/* ����� ��� �������� */\r\nbody {\r\n    background-color: #C0C0C0;\r\n    margin: 0;\r\n    padding: 0;\r\n    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', sans-serif;\r\n}\r\n\r\n.container {\r\n    margin: 0 auto;\r\n    max-width: 1200px;\r\n    padding: 0 48px;\r\n}\r\n\r\n/* ��������� �������� (�����/������) */\r\n.section-title {\r\n    font-size: 48px;\r\n    font-weight: bold;\r\n    color: #1a5d2e;\r\n    margin: 0;\r\n    flex: 1;\r\n    text-align: center;\r\n}\r\n\r\n/* ��������� ��� ����� ���������� */\r\n.add-form {\r\n    display: flex;\r\n    gap: 12px;\r\n    margin-top: 48px;\r\n    align-items: center;\r\n}\r\n\r\n/* ���� ����� */\r\n.add-task {\r\n    flex: 1;\r\n    background-color: #f0f8e8;\r\n    border: 2px solid #2e8b57;\r\n    padding: 16px 32px;\r\n    font-size: 24px;\r\n    line-height: 40px;\r\n    color: #1a5d2e;\r\n    border-radius: 64px;\r\n    outline: none;\r\n    transition: all 0.3s ease;\r\n}\r\n\r\n    .add-task:focus {\r\n        border-color: #236b43;\r\n        box-shadow: 0 0 0 3px rgba(46, 139, 86, 0.15);\r\n    }\r\n\r\n    .add-task::placeholder {\r\n        color: #b0c4b0;\r\n    }\r\n\r\n/* ���������� ������ */\r\n.media-type-select {\r\n    background-color: #f0f8e8;\r\n    border: 2px solid #2e8b57;\r\n    padding: 16px 24px;\r\n    font-size: 24px;\r\n    border-radius: 64px;\r\n    color: #f0f8e8;\r\n    cursor: pointer;\r\n    outline: none;\r\n    transition: all 0.3s ease;\r\n}\r\n\r\n    .media-type-select:focus {\r\n        border-color: #236b43;\r\n        box-shadow: 0 0 0 3px rgba(46, 139, 86, 0.15);\r\n    }\r\n\r\n/* ������ ���������� */\r\n.add-btn {\r\n    background-color: #2e8b57 !important;\r\n    border: none;\r\n    border-radius: 64px;\r\n    padding: 16px 32px;\r\n    font-size: 32px;\r\n    font-weight: bold;\r\n    color: #f0f8e8;\r\n    cursor: pointer;\r\n    transition: all 0.2s;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    min-width: 80px;\r\n}\r\n\r\n    .add-btn:hover {\r\n        background-color: #f0f8e8;\r\n        transform: scale(1.02);\r\n    }\r\n\r\n/* ������� ������ (��������) */\r\n.task-item {\r\n    margin-bottom: 24px;\r\n    border-radius: 24px;\r\n    display: flex;\r\n    justify-content: space-between;\r\n    align-items: flex-start;\r\n    background-color: #f0f8e8;\r\n    border: 2px solid #2e8b57;\r\n    padding: 24px 32px;\r\n    transition: all 0.3s ease;\r\n    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.05);\r\n}\r\n\r\n    .task-item:hover {\r\n        transform: translateY(-2px);\r\n        box-shadow: 0 8px 20px rgba(46, 139, 86, 0.15);\r\n        border-color: #236b43;\r\n    }\r\n\r\n/* ������� ������ �������� */\r\n.task-content {\r\n    flex: 1;\r\n}\r\n\r\n/* ������� ������ �������� */\r\n.task-header {\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 16px;\r\n    flex-wrap: wrap;\r\n}\r\n\r\n/* ����� �������� */\r\n.task-number {\r\n    font-weight: bold;\r\n    font-size: 28px;\r\n    color: #2e8b57;\r\n    min-width: 40px;\r\n}\r\n\r\n/* ������ ���� */\r\n.task-icon {\r\n    font-size: 32px;\r\n}\r\n\r\n/* �������� �������� */\r\n.task-title {\r\n    font-size: 28px;\r\n    font-weight: 500;\r\n    color: #1a5d2e;\r\n    flex: 1;\r\n}\r\n\r\n/* ������ �������� */\r\n.delete-btn {\r\n    background-color: #236b43;\r\n    border: none;\r\n    border-radius: 16px;\r\n    padding: 8px 20px;\r\n    color: white;\r\n    cursor: pointer;\r\n    font-size: 18px;\r\n    transition: all 0.2s;\r\n}\r\n\r\n    .delete-btn:hover {\r\n        background-color: #1a5d2e;\r\n        transform: translateY(-1px);\r\n    }\r\n\r\n/* ������ ������  */\r\n.review-btn {\r\n    background-color: #98FB98;\r\n    border: none;\r\n    border-radius: 16px;\r\n    padding: 8px 20px;\r\n    color: white;\r\n    cursor: pointer;\r\n    font-size: 18px;\r\n    transition: all 0.2s;\r\n}\r\n\r\n    .review-btn:hover {\r\n        background-color: #236b43;\r\n        transform: translateY(-1px);\r\n    }\r\n\r\n/* ������ \"�����\" */\r\n.back-btn {\r\n    background-color: #1a5d2e;\r\n    border: none;\r\n    padding: 12px 24px;\r\n    font-size: 18px;\r\n    border-radius: 32px;\r\n    color: white;\r\n    cursor: pointer;\r\n    transition: all 0.2s;\r\n}\r\n\r\n    .back-btn:hover {\r\n        background-color: #0d4a23;\r\n        transform: translateX(-3px);\r\n    }\r\n\r\n/* ������ ������� ���� */\r\n.clear-all-btn {\r\n    height: 72px;\r\n    width: 72px;\r\n    padding: 0;\r\n    margin-top: 48px;\r\n    background-color: #3cb371;\r\n    border: none;\r\n    border-radius: 50%;\r\n    color: white;\r\n    font-size: 32px;\r\n    cursor: pointer;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    flex-shrink: 0;\r\n    transition: all 0.2s;\r\n}\r\n\r\n    .clear-all-btn:hover {\r\n        background-color: #2e8b57;\r\n        transform: scale(1.05);\r\n    }\r\n\r\n/* ��������� ��� ������ */\r\n.notes {\r\n    margin: 36px 0 144px;\r\n    padding: 0;\r\n    list-style: none;\r\n}\r\n\r\n/* ����� ������ �������� */\r\n.review-text {\r\n    margin-top: 16px;\r\n    padding: 12px 20px;\r\n    background-color: #ffffff;\r\n    border-radius: 16px;\r\n    font-size: 18px;\r\n    font-style: italic;\r\n    border-left: 4px solid #2e8b57;\r\n    color: #1a5d2e;\r\n}\r\n\r\n/* ��������� ������� */\r\n.section-header {\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: space-between;\r\n    margin: 32px 0;\r\n    gap: 20px;\r\n}\r\n\r\n/* ������������ */\r\n@media (max-width: 768px) {\r\n    .container {\r\n        padding: 0 20px;\r\n    }\r\n\r\n    .add-form {\r\n        flex-wrap: wrap;\r\n    }\r\n\r\n    .add-task,\r\n    .media-type-select {\r\n        font-size: 18px;\r\n        padding: 12px 20px;\r\n    }\r\n\r\n    .add-btn {\r\n        font-size: 24px;\r\n        padding: 12px 24px;\r\n        min-width: 60px;\r\n    }\r\n\r\n    .task-item {\r\n        padding: 16px 20px;\r\n    }\r\n\r\n    .task-title {\r\n        font-size: 20px;\r\n    }\r\n\r\n    .task-number {\r\n        font-size: 20px;\r\n    }\r\n\r\n    .section-title {\r\n        font-size: 32px;\r\n    }\r\n\r\n    .back-btn {\r\n        padding: 8px 16px;\r\n        font-size: 14px;\r\n    }\r\n}\r\n","\r\n.welcome-screen {\r\n    min-height: 100vh;\r\n    background-color: #C0C0C0;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    padding: 20px;\r\n}\r\n\r\n.welcome-container {\r\n    max-width: 800px;\r\n    width: 100%;\r\n    text-align: center;\r\n}\r\n\r\n.welcome-title {\r\n    font-size: 64px;\r\n    font-weight: bold;\r\n    color: #1a5d2e;\r\n    margin-bottom: 16px;\r\n}\r\n\r\n.welcome-subtitle {\r\n    font-size: 24px;\r\n    color: #4a6b5a;\r\n    margin-bottom: 48px;\r\n}\r\n\r\n.section-buttons {\r\n    display: grid;\r\n    grid-template-columns: 1fr 1fr;\r\n    gap: 30px;\r\n}\r\n\r\n.section-btn {\r\n    background: #f0f8e8;\r\n    border: 2px solid #2e8b57;\r\n    border-radius: 20px;\r\n    padding: 40px 20px;\r\n    cursor: pointer;\r\n    transition: all 0.3s ease;\r\n    text-align: center;\r\n}\r\n\r\n    .section-btn:hover {\r\n        transform: translateY(-5px);\r\n        border-color: #f0f8e8;\r\n        background-color: #f0fff4;\r\n        box-shadow: 0 10px 30px rgba(46, 139, 86, 0.15);\r\n    }\r\n\r\n.btn-icon {\r\n    font-size: 80px;\r\n    display: block;\r\n    margin-bottom: 20px;\r\n}\r\n\r\n.btn-title {\r\n    font-size: 32px;\r\n    font-weight: bold;\r\n    display: block;\r\n    margin-bottom: 10px;\r\n    color: #1a5d2e;\r\n}\r\n\r\n.btn-desc {\r\n    font-size: 16px;\r\n    color: #4a6b5a;\r\n}\r\n\r\n@media (max-width: 768px) {\r\n    .section-buttons {\r\n        grid-template-columns: 1fr;\r\n        gap: 20px;\r\n    }\r\n\r\n    .welcome-title {\r\n        font-size: 48px;\r\n    }\r\n\r\n    .welcome-subtitle {\r\n        font-size: 20px;\r\n    }\r\n\r\n    .btn-icon {\r\n        font-size: 60px;\r\n    }\r\n\r\n    .btn-title {\r\n        font-size: 28px;\r\n    }\r\n}\r\n"],"names":[],"sourceRoot":""}